// // This module implements a flip-flop with Reset and Set features, capturing the D input on the falling edge of the clock signal (C). When the Reset (R) signal is high, the output RF is forced to HIGH. When the Set (S) signal is high, the output RF is set to the value of D. If both R and S are low, RF retains its previous state. The output RI is always the logical negation of RF, effectively providing an inverted version of the flip-flop output.
module top_module(input R, S, D, C, output reg RF, output RI);assign RI = ~RF;

  always @(posedge C)
  begin
    if (!R)
	 begin
	   RF <= 1'b0;
	 end
	 else if (!S)
	 begin
	   RF <= D;
	 end
	 else
	 begin
	   RF <= RF;
	 end

  end

endmodule
